      switch rawValue {
      case 0: self = .none
      case 1: self = .fajr
      case 2: self = .sunrise
      case 3: self = .zuhr
      case 4: self = .asr
      case 5: self = .maghrib
      case 6: self = .isha
      default: self = .UNRECOGNIZED(rawValue)
      }
    }

    public var rawValue: Int {
      switch self {
      case .none: return 0
      case .fajr: return 1
      case .sunrise: return 2
      case .zuhr: return 3
      case .asr: return 4
      case .maghrib: return 5
      case .isha: return 6
      case .UNRECOGNIZED(let i): return i
      }
    }

